{
  "nodes": [{
    "parameters": {
      "agent": "toolsAgent",
      "model": "gpt-4o",
      "tools": [{
        "type": "code",
        "name": "generateCode",
        "description": "Generate executable code for the task",
        "schema": {
          "type": "object",
          "properties": {
            "code": { "type": "string" },
            "language": { "type": "string", "enum": ["typescript", "python"] }
          }
        }
      }],
      "prompt": "Generate TypeScript code to fetch weather data from OpenWeatherMap API"
    },
    "type": "n8n-nodes-langchain.agent"
  }],
  "connections": { "AI Agent": { "main": [[{ "node": "Vex Webhook" }]] } }
}

// n8n webhook node configuration
const vexWebhookUrl = "https://api.vex.dev/v1/verify";

return {
  method: "POST",
  url: vexWebhookUrl,
  body: {
    sessionId: "{{ $json.sessionId }}",
    payload: $json,
    checks: ["code_safety", "syntax_validity", "no_secrets", "sandbox_safe"]
  },
  headers: {
    "Authorization": "Bearer " + $env.VEX_API_KEY,
    "Content-Type": "application/json"
  }
};

// Conditional execution after Vex webhook
if ($json.vex?.approved !== true) {
  throw new Error(`Vex blocked unsafe code: ${$json.vex.reason}`);
}

return {
  code: $json.payload.code,
  language: $json.payload.language,
  timeout: 10000,
  sandbox: true
};

// Test results node
const testsPassed = $json.tests.every(t => t.passed);

if (!testsPassed) {
  return {
    feedback: $json.tests.map(t => t.error).join('\n'),
    action: "retry",
    memory: {
      previousCode: $json.code,
      testFailures: $json.tests
    }
  };
}

return { status: "approved", deploy: $json.code };

