import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'n8n-code-gen'
});

const result = await vex.verify({
  sessionId: $input.first().json.sessionId,
  payload: {
    code: $input.first().json.code,
    language: 'typescript'
  },
  checks: [
    'code_safety',
    'syntax_validity',
    'no_credential_leakage',
    'sandbox_execution_safe',
    'dependency_safety'
  ]
});

return {
  vexId: result.id,
  approved: result.approved,
  reason: result.reason,
  safeCode: result.verifiedPayload
};

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: $env.VEX_API_KEY });

const check = await vex.check({
  type: 'code_safety',
  payload: {
    code: $input.code,
    context: 'n8n AI agent output',
    riskProfile: 'high'
  }
});

if (!check.safe) {
  return {
    block: true,
    violations: check.issues,
    remediation: check.suggestions
  };
}

return { safe: true, verifiedCode: check.payload };

import { Vex } from '@vex_dev/sdk';

const session = new Vex.Session('code-gen-session');

await session.record({
  step: 'pre-sandbox',
  payload: {
    code: $input.code,
    deps: $input.dependencies || [],
    timeout: 30
  }
});

const sandboxCheck = await session.verify({
  checks: ['execution_sandboxing', 'dependency_safety'],
  maxMemory: '256MB',
  allowedImports: ['axios', 'lodash']
});

return {
  sandboxApproved: sandboxCheck.approved,
  traceId: sandboxCheck.traceId,
  executionPlan: sandboxCheck.plan
};
